    "tool.scope.hint": "Componente codifica caracteres reservados como ? & = / # — use-o para valores de consulta e segmentos de caminho. URL completa mantém esses caracteres estruturais intactos para codificar um endereço inteiro.",
    "tool.form": "Codificação de formulário (espaço → +)",
    "tool.textLabel": "Texto",
    "tool.textPlaceholder": "Digite ou cole o texto a codificar…",
    "tool.urlLabel": "URL codificada",
    "tool.urlPlaceholder": "Cole uma string %-codificada para decodificar…",
    "tool.copy": "Copiar",
